void MRFTWIAndNSDDlg::BuildSurfaceList()
{
	_pSurfaceListDlg = new CATDlgDialog(this, "TWI Surfaces", CATDlgGridLayout | CATDlgWndNoButton | CATDlgWndNoResize);
	if (NULL != _pSurfaceListDlg)
	{
		_pSurfaceMultiList = new CATDlgMultiList(_pSurfaceListDlg, (const char*)"SelectedSurfaces");
		if (NULL != _pSurfaceMultiList)
		{
			_pSurfaceListCtxMenu = new CATDlgContextualMenu(_pSurfaceMultiList, CATString("CtxMenu"), CATDlgCtxEmpty);

			_pSurfaceMultiList->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

			CATUnicodeString strHeader[1];
			strHeader[0] = "Surfaces";

			_pSurfaceMultiList->SetColumnTitles(1, strHeader);
			_pSurfaceMultiList->SetColumnTextWidth(0, 15);
			_pSurfaceMultiList->SetVisibleLineCount(5);
			_pSurfaceMultiList->SetVisibleColumnCount(1);
			_pSurfaceMultiList->SetTitlesVisibility(TRUE);
		}
	}
}

void MRFTWIAndNSDDlg::ClearOtherSelections(CATString istrData)
{
	if (istrData == "TWIProfile")
	{
		if (_pManufacturingType)
			_pManufacturingType->ClearSelect();
		if (_pTWISurfaceSelector)
			_pTWISurfaceSelector->ClearSelect();
		if (_pCuttingPlaneSelector)
			_pCuttingPlaneSelector->ClearSelect();
		if (_pNSDTWISetSelector)
			_pNSDTWISetSelector->ClearSelect();
	}
	else if (istrData == "TWISurface")
	{
		if (_pTWIProfileType)
			_pTWIProfileType->ClearSelect();
		if (_pManufacturingType)
			_pManufacturingType->ClearSelect();
		if (_pCuttingPlaneSelector)
			_pCuttingPlaneSelector->ClearSelect();
		if (_pNSDTWISetSelector)
			_pNSDTWISetSelector->ClearSelect();
	}
	else if (istrData == "TWICuttingPlane")
	{
		if (_pTWIProfileType)
			_pTWIProfileType->ClearSelect();
		if (_pManufacturingType)
			_pManufacturingType->ClearSelect();
		if (_pTWISurfaceSelector)
			_pTWISurfaceSelector->ClearSelect();
		if (_pNSDTWISetSelector)
			_pNSDTWISetSelector->ClearSelect();
	}
	else if (istrData == "NSDTWISet")
	{
		if (_pTWIProfileType)
			_pTWIProfileType->ClearSelect();
		if (_pTWISurfaceSelector)
			_pTWISurfaceSelector->ClearSelect();
		if (_pCuttingPlaneSelector)
			_pCuttingPlaneSelector->ClearSelect();
		if (_pManufacturingType)
			_pManufacturingType->ClearSelect();
	}
	else if (istrData == "NSDManufType")
	{
		if (_pTWIProfileType)
			_pTWIProfileType->ClearSelect();
		if (_pTWISurfaceSelector)
			_pTWISurfaceSelector->ClearSelect();
		if (_pCuttingPlaneSelector)
			_pCuttingPlaneSelector->ClearSelect();
		if (_pNSDTWISetSelector)
			_pNSDTWISetSelector->ClearSelect();
	}
	else if (istrData == "All")
	{

		if (_pTWIProfileType)
			_pTWIProfileType->ClearSelect();
		if (_pTWISurfaceSelector)
			_pTWISurfaceSelector->ClearSelect();
		if (_pCuttingPlaneSelector)
			_pCuttingPlaneSelector->ClearSelect();
		if (_pNSDTWISetSelector)
			_pNSDTWISetSelector->ClearSelect();
		if (_pManufacturingType)
			_pManufacturingType->ClearSelect();
	}

}

void MRFTWIAndNSDDlg::UpdateSelectorList(CATString istrListData, CATUnicodeString iStringLine)
{
	CATDlgSelectorList * pSelector = NULL;
	if (istrListData == "TWISurface")
	{
		pSelector = _pTWISurfaceSelector;
	}
	else if (istrListData == "TWICuttingPlane")
	{
		pSelector = _pCuttingPlaneSelector;
	}
	else if (istrListData == "NSDTWISet")
	{
		pSelector = _pNSDTWISetSelector;
	}
	
	if (NULL != pSelector)
	{
		pSelector->ClearLine();
		pSelector->SetLine(iStringLine);

		int select = 0;
		pSelector->SetSelect(&select, 1);

		if (istrListData == "TWISurface" && "No Surface Selected" == iStringLine)
		{
			_pSurfaceMultiList->ClearLine();
		}

	}
}

