void MRFTWIAndNSDDlg::SetNSDValuesOfSpinners(double dNSDHeight, double dNSDWidth, double dStartPosition, int dNSDManufactType, double &_dNSDPaddingAngle1, double &_dNSDPaddingAngle2, double &_dNSDSpacing)
{
	_pNSDHeight->SetCurrentValue((float)dNSDHeight,0);
	_pNSDWidth->SetCurrentValue((float)dNSDWidth, 0);
	_pStartPosition->SetCurrentValue((float)dStartPosition, 0);
	_pManufacturingType->SetSelect(dNSDManufactType, 0);
	_pNSDPaddingAngle1->SetCurrentValue((float)_dNSDPaddingAngle1, 0);
	_pNSDPaddingAngle2->SetCurrentValue((float)_dNSDPaddingAngle2, 0);
	_pNSDSpacing->SetCurrentValue((float)_dNSDSpacing, 0);
}
